+/**
+ * Check a CLI tool with timeout.
+ */
+async function checkCLI(
+  name: string,
+  command: string[],
+  timeoutMs = 5000,
+): Promise<ComponentHealth> {
+  const startTime = performance.now();
+
+  try {
+    const proc = Bun.spawn(command, {
+      stdout: "pipe",
+      stderr: "pipe",
+      env: { ...process.env, NO_COLOR: "1" },
+    });
+
+    // Create timeout promise
+    const timeout = new Promise<never>((_, reject) => {
+      setTimeout(() => reject(new Error("Timeout")), timeoutMs);
+    });
+
+    // Race between command and timeout
+    const result = await Promise.race([
+      (async () => {
+        const stdout = await new Response(proc.stdout).text();
+        const exitCode = await proc.exited;
+        return { stdout, exitCode };
+      })(),
+      timeout,
+    ]);
+
+    const latencyMs = Math.round(performance.now() - startTime);
+
+    if (result.exitCode === 0) {
+      // Extract version from output
+      const versionMatch = result.stdout.match(
+        /v?(\d+\.\d+(?:\.\d+)?(?:-[\w.]+)?)/,
+      );
+      const version = versionMatch ? versionMatch[0] : undefined;
+      return {
+        status: "healthy",
+        message: `${name} available`,
+        latencyMs,
+        ...(version && { version }),
+      };
+    }
+
+    return {
+      status: "unhealthy",
+      message: `${name} exited with code ${result.exitCode}`,
+      latencyMs,
+    };
+  } catch (error) {
+    const latencyMs = Math.round(performance.now() - startTime);
+    const message =
+      error instanceof Error && error.message === "Timeout"
+        ? `${name} check timed out`
+        : `${name} not available`;
+
+    return {
+      status: "unhealthy",
+      message,
+      latencyMs,
+    };
+  }
